有关下面 C++ 代码的说法，正确的是（ ）。

```cpp
#include <iostream>
using namespace std;

class ManyData {
    int __data[10];
    int __size;
public:
    ManyData() : __size(0) {}
    void push(int val) {
        __data[__size] = val;
        __size++;
    }
    int pop() {
        __size--;
        return __data[__size];
    }
    int size() { return __size; }
};

int main() {
    ManyData myData;
    myData.push(1);
    myData.push(2);
    myData.push(3);
    cout << myData.pop() << endl;
    cout << myData.pop() << endl;
    cout << myData.pop() << endl;
    return 0;
}
```
